import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


NEW_DATA = {"119": {"1": "<p><b>ALEPH — ashre tamime-darekh</b> — <i>ashre</i> (blessed/happy) opens both this psalm and the Psalter (Ps 1:1), forming a grand inclusio. <i>tamim-darekh</i> (blameless of way) uses <i>tamim</i> (the Noah/Abraham wholeness word: Gen 6:9; 17:1) applied to the path of life. <i>btorat YHWH</i> (in the instruction/Torah of the LORD) — blamelessness is not an inner achievement but a path walked within the covenant structure of Torah. The psalm's thesis: blessed life is life shaped entirely by divine instruction.</p>", "2": "<p><b>ashre nozre edotayw</b> — <i>edot</i> (decrees/testimonies, from <i>ud</i>, to bear witness) — covenant stipulations that testify to God's character. <i>bkol-lev</i> (with the whole heart) — repeated throughout Ps 119: the Law is not a system to be gamed but a relationship to be inhabited wholly. <i>yidreshuhhu</i> (they seek/pursue him) — <i>darash</i> (to seek, pursue diligently) — the decrees are kept as the path toward the person of YHWH himself.</p>", "3": "<p><b>lo-palu avlah bidrakhav halakhu</b> — uniquely, this verse lacks an explicit Torah-synonym, using instead <i>derachav</i> (his ways). <i>avlah</i> (wrongdoing, moral perversity) — the word for injustice violating both covenant and neighbor. The blameless person is described negatively (they do nothing wrong) and positively (they walk in his ways): blamelessness is a pattern of walking, not a catalog of rules.</p>", "4": "<p><b>attah tzivvita piqqudecha lishmore meod</b> — <i>piqqudim</i> (precepts/mandates, from <i>paqad</i>, to visit/appoint/oversee) — specific applications of covenant instruction to particular situations. <i>meod</i> (greatly, very much) modifies <i>lishmor</i> (to keep): careful keeping is diligent, thorough attention. The verse acknowledges divine initiative: God commanded (<i>tzivvita</i>) — the precepts are given, not invented.</p>", "5": "<p><b>achale yikonu derachai lishmore chuqqecha</b> — <i>achale</i> (would that!/if only — the optative particle expressing earnest wish) — rare and emphatic; the psalm's first personal confession of imperfection. <i>chuqqim</i> (statutes, from <i>chaqaq</i>, to inscribe/engrave) — decrees carved permanently into covenant life. The optative mood is key: the psalmist does not claim to keep the statutes perfectly but longs to. The tension between aspiration and reality runs through all 176 verses.</p>", "6": "<p><b>az lo-evosh behabbiti el-kol-mitzvotecha</b> — <i>mitzvot</i> (commandments, from <i>tzavah</i>, to command). <i>az lo-evosh</i> (then I would not be ashamed) — <i>bosh</i> (shame) is the social experience of being publicly exposed as having failed the community's standard. The motivational logic: Torah-keeping produces no shame because alignment with God's character requires no hiding.</p>", "7": "<p><b>odecha beyosher levav belomdi mishpetei tzidqechah</b> — <i>mishpetei tzidqechah</i> (your righteous decrees/judgments) — <i>mishpat</i> (judgment/ordinance) qualified by <i>tzedqah</i>: these are not arbitrary rulings but righteous ones. <i>yashar levav</i> (upright/straight heart) — praise is the natural expression of a heart aligned with the decrees it is learning. Learning and praise are simultaneous, not sequential.</p>", "8": "<p><b>et-chuqqecha eshmor al-taazeveni ad-meod</b> — the Aleph stanza closes with vulnerability: <i>al-taazeveni</i> (do not abandon me, negative jussive of <i>azav</i>) — the same word for abandonment used in Ps 22:1. <i>ad-meod</i> (to a great/extreme degree) intensifies the plea. The stanza opens with blessing (v1) and closes with a cry against abandonment (v8) — the psalm sustains this tension between aspiration and dependence throughout.</p>", "9": "<p><b>BETH — bameh yizakke naar et-orcho lishmor kimratechah</b> — <i>yizakke</i> (keep pure, Piel of <i>zakah</i> = to be clean, free from guilt). <i>naar</i> (young man/youth) — the intended audience of Proverbs-style wisdom. <i>imratechah</i> (your word/saying, from <i>amar</i>) — the most intimate Torah-synonym: not statute or law but personal utterance, word spoken by God. The answer to the young person's dilemma is not moral effort but alignment with the divine word.</p>", "10": "<p><b>bkol-libbi derashtichah</b> — <i>kol-libbi</i> (with all my heart) — the whole-heart formula for covenant devotion (Deut 6:5). <i>derashtichah</i> (I have sought/pursued you, Qal perfect of <i>darash</i>) — the object is God as person: 'I sought you,' not Torah as object. <i>al-tashgeni</i> (do not let me stray, negative jussive Hiphil of <i>shagah</i>) — <i>shagah</i> means to wander, go astray. The plea: keep the whole-heart pursuit from drifting.</p>", "11": "<p><b>blibbi tzafanti imratechah</b> — <i>tzafanti</i> (I have hidden/stored up, Piel of <i>tzaphan</i>) — the intensive form of hiding: to conceal carefully for future use, as treasure is hidden. <i>imratechah</i> — the personal divine utterance stored in the personal human heart. <i>lema'an lo-echeta-lach</i> (so that I will not sin against you) — the purpose: internalized word preempts sin. The Piel suggests not passive remembering but active, deliberate concealment within the heart.</p>", "12": "<p><b>baruch attah YHWH lammadeni chuqqecha</b> — <i>baruch attah YHWH</i> (blessed are you, O LORD) — the benediction formula of liturgical tradition appears mid-psalm in personal prayer. <i>lammadeni</i> (teach me, Piel imperative of <i>lamad</i>) — the Piel is causative-intensive: cause me to learn thoroughly. The juxtaposition of blessing-ascription and learning-petition shows that praising God and requesting instruction are the same act.</p>", "13": "<p><b>bisfatai sipparti kol-mishpete ficha</b> — <i>sipparti</i> (I have rehearsed/declared, Piel of <i>saphar</i> = to count, recount) — the intensive telling of all divine judgments. <i>mishpete ficha</i> (all the decrees of your mouth) — the mouth (<i>peh</i>) personalizes the decrees: words that come from YHWH's own mouth. The lips that rehearse the divine decrees become aligned with the divine mouth.</p>", "14": "<p><b>bderekh edotechah sasti keal kol-hon</b> — <i>sasti</i> (I have rejoiced, Qal perfect of <i>sus</i>). <i>keal kol-hon</i> (as over all riches/wealth) — <i>hon</i> (wealth, abundance) — the decrees are valued above every material acquisition. The economic comparison ('as if I found great riches') will recur in v162 (great spoil).</p>", "15": "<p><b>bpiqqudecha asicha veabbitah orchotechah</b> — <i>asicha</i> (I will meditate, Qal cohortative of <i>asah</i>) — meditation is voiced self-talk, rehearsal aloud, not silent internal processing. <i>veabbitah</i> (and I will contemplate, Hiphil of <i>nabat</i> = to look intently) — two verbs of sustained attention: audible meditation and intent visual focus on the path.</p>", "16": "<p><b>bechuqqotechah eshataasha devarecha lo-eshkach</b> — <i>eshataasha</i> (I will delight, Hithpael of <i>shaashua</i>) — the reflexive-intensive form: I will cause myself to delight, cultivate pleasure in your statutes. <i>devarecha lo-eshkach</i> (your word I will not forget) — the Beth stanza closes with the negative commitment not to forget (<i>shakhach</i>). The Hithpael of <i>shaashua</i> appears six times in Ps 119, suggesting habitually cultivated delight.</p>", "17": "<p><b>GIMEL — gemal al-avdecha veechyeh veeshmorah devarecha</b> — <i>gemal</i> (deal generously with, Qal imperative of <i>gamal</i>) — God's dealing with the servant is framed as <i>gemilut chassadim</i> (acts of loving-kindness). <i>veechyeh</i> (so I may live) — the purpose of divine generosity is life. <i>devarecha eshmorah</i> (I will keep your word) — life is the precondition for keeping the word: the request is that God sustain life so that obedience continues.</p>", "18": "<p><b>gal-einai veabbitah niphleot mitoratechah</b> — <i>gal-einai</i> (uncover/open my eyes, Piel imperative of <i>galah</i>) — <i>galah</i> primarily means to uncover, reveal, go into exile. Applied to eyes it asks for the removal of a covering. <i>niphleot</i> (wonders/marvelous things, Niphal participle of <i>pala</i>) — the Torah contains wonders not accessible by ordinary reading but requiring divine eye-opening — a pneumatological claim about Scripture.</p>", "19": "<p><b>ger anochi vaaretz al-taster mimmeni mitzvotecha</b> — <i>ger anochi</i> (I am a sojourner/foreigner on the earth) — <i>ger</i> (resident alien) had specific legal status: dependent on host-community hospitality, without permanent land rights. The psalmist identifies existentially as a <i>ger</i> — the ultimate home is elsewhere. <i>al-taster mitzvotecha</i> (do not hide your commandments from me) — a sojourner needs the community's instructions; exile from Torah would compound the alienation.</p>", "20": "<p><b>garsa naphshi letaavah el-mishpatecha bkol-et</b> — <i>garsa</i> (is worn away/crushed with longing, Qal perfect of <i>garas</i> = to crush, grind) — an intense physical metaphor: the soul is ground down by its craving. <i>taavah</i> (craving) is the same word used for Israel's deadly craving of meat in the wilderness (Num 11:4) — here redeployed for righteous desire of divine ordinances.</p>", "21": "<p><b>gaarta zedim arurim hashogim mimitzvotechah</b> — <i>gaarta</i> (you rebuked, Qal perfect of <i>gaar</i>) — the divine rebuke word used for chaos waters (Ps 104:7) and enemies; here for the arrogant who stray from Torah. <i>arurim</i> (accursed) — the covenantal curse falls specifically on those who wander (<i>shogim</i>, Qal participle of <i>shagah</i>) from the commandments.</p>", "22": "<p><b>gol mealai cherpah vabuz ki edotechah natzerti</b> — <i>gol mealai</i> (roll away from upon me, Qal imperative of <i>galal</i>) — reproach as a heavy object to be rolled away. <i>cherpah vabuz</i> (reproach and contempt) — the social shame vocabulary. The psalmist has kept the decrees yet experiences shame rather than vindication. The request: let keeping the decrees result in vindication.</p>", "23": "<p><b>gam yashevu sarim bidabberu bi avdecha yasich bechuqqecha</b> — <i>sarim</i> (princes/officials) conspire against the psalmist. <i>bidabberu bi</i> (in their speaking against me) — official slander from power. The response: <i>avdecha yasich bechuqqecha</i> (your servant meditates on your statutes) — not political counter-action but sustained attention to the divine word. Rulers plot; the servant meditates.</p>", "24": "<p><b>gam edotecha shaashuai anshei atzati</b> — <i>shaashuai</i> (my delight) — the noun form of the Hithpael verb from vv15-16. <i>anshei atzati</i> (my counselors) — the decrees are personified as advisors: the psalmist takes advice from Torah as one consults trusted counselors. Divine decrees possess the practical wisdom that politicians seek.</p>", "25": "<p><b>DALETH — davqah leapar naphshi chayyeni kidvarecha</b> — <i>davqah</i> (clings/is stuck, Qal perfect of <i>davaq</i>) — the covenant-intimacy and marriage-union word (Gen 2:24; Ruth 1:14) inverted: the soul clings not to God but to the dust (<i>apar</i>) of death and despair. <i>leapar</i> (to the dust) — the death-return phrase of Gen 3:19. The depth of crisis: the intimacy-word is now attached to mortality. <i>chayyeni kidvarecha</i> — the only counter-force to dust-clinging is the life-giving word.</p>", "26": "<p><b>derachai sipparti vatishma lammadeni chuqqecha</b> — <i>derachai sipparti</i> (I laid out my ways) — full transparency before God: the psalmist spreads out the path for divine scrutiny. <i>vatishma</i> (and you heard, Qal perfect) — divine hearing is established before the request for teaching: God listened, now teach. The sequence of confession-then-teaching models the prayer dynamic.</p>", "27": "<p><b>derekh-piqqudecha havineni veaasichah beniphleotecha</b> — <i>havineni</i> (give me understanding, Hiphil imperative of <i>bin</i>) — the Hiphil is causative: cause me to understand. <i>beniphleotecha</i> (your wonderful deeds) — the result of understanding the path of the precepts is contemplation of God's wonders. Torah-understanding leads to amazement at God himself.</p>", "28": "<p><b>dalpha naphshi mitugah qaymeni kidvarecha</b> — <i>dalpha</i> (drips/dissolves, Qal perfect of <i>dalaph</i> = to drip, weep) — an unusually physical grief-image: the soul leaks from sorrow as a leaking vessel. <i>qaymeni</i> (raise me up, Hiphil imperative of <i>qum</i>) — the request for resurrection from the dissolving: the word that created upright life must restore it.</p>", "29": "<p><b>derekh-sheqer aser mimmeni vetoratecha chonneni</b> — <i>derekh-sheqer</i> (the path/way of falsehood) — <i>sheqer</i> (deception, emptiness, lie) — the antithesis of <i>emet</i>. <i>aser</i> (remove, Hiphil imperative of <i>sur</i>) — an active removal: the false path must be displaced, not merely avoided. <i>vetoratecha chonneni</i> (graciously give me your Torah) — <i>chanan</i> (to be gracious) applied to Torah: the Law itself is received as gift.</p>", "30": "<p><b>derekh-emunah bacharti mishpatecha shivviti</b> — <i>derekh-emunah</i> (the path of faithfulness/truth) — <i>emunah</i> (faithfulness, reliability, firmness — from <i>aman</i>, the root of <i>amen</i>) — not abstract truth but the track record of reliable covenant faithfulness. <i>bacharti</i> (I have chosen, Qal perfect of <i>bachar</i>) — the election-verb turned personal: just as God chooses Israel, the psalmist chooses the faithful path.</p>", "31": "<p><b>davaqti bedotechah YHWH al-tivisheni</b> — <i>davaqti</i> (I have clung, Qal perfect of <i>davaq</i>) — returning to the <i>davaq</i> root from v25: there the soul clung to the dust; here to the decrees. The stanza's inclusio: <i>davaq</i>-to-dust (v25) reversed to <i>davaq</i>-to-decrees (v31). <i>al-tivisheni</i> (do not put me to shame) — the clinging to decrees should issue in vindication, not shame.</p>", "32": "<p><b>derekh mitzvotechah arutz ki tarchiv libbi</b> — <i>arutz</i> (I will run, Qal cohortative of <i>rutz</i>) — running the commandment-path is the energy of covenant life. <i>ki tarchiv libbi</i> (when you enlarge my heart, Hiphil of <i>rachav</i>) — <i>rachav</i> (wide/broad) echoes the <i>marchav</i> of Ps 118:5: rescue is experienced as spaciousness. From soul-clinging-to-dust (v25) to running with an enlarged heart (v32) — all by divine liberation.</p>", "33": "<p><b>HE — horeni YHWH derekh chuqqecha veetzerenah eqev</b> — <i>horeni</i> (teach me, Hiphil imperative of <i>yrah</i>) — the root of <i>tôrāh</i> (instruction): to ask God to teach is to ask for Torah at its source. <i>veetzerenah eqev</i> (and I will follow it to the very end) — <i>eqev</i> (heel, consequence, end) — all the way to the last step. Teaching must begin with God: no human initiative produces Torah-walking.</p>", "34": "<p><b>havineni veeetzerenah toratechah veeshmor bekhol-libbi</b> — <i>havineni</i> (give me understanding, Hiphil of <i>bin</i>) — understanding is the prerequisite for keeping. <i>bekhol-libbi</i> (with all my heart) — the whole-heart formula: understanding without whole-heart application is not the goal. The psalm's anthropology: keeping requires understanding, and understanding requires heart.</p>", "35": "<p><b>hadricheni benatib mitzvotechah ki-vo chafatzti</b> — <i>hadricheni</i> (guide/lead me, Hiphil imperative of <i>darakh</i> = to tread, walk, guide). <i>benatib</i> (in the path/track) — <i>natib</i> is a worn path made by repeated walking. <i>ki-vo chafatzti</i> (for in it is my delight) — <i>chafetz</i> (delight, desire) — the commandment-path is desired, not merely obeyed.</p>", "36": "<p><b>hath-libbi el-edotechah veal el-betza</b> — <i>hath-libbi</i> (turn/incline my heart, Hiphil imperative of <i>natah</i>) — God must turn the heart toward the decrees; the human cannot simply redirect the heart by will. <i>veal el-betza</i> (and not toward selfish gain/dishonest profit) — <i>betza</i> (unjust gain, greed). The heart has only two directions: toward the decrees or toward self-serving gain.</p>", "37": "<p><b>haaver einai mireot shav bichraqecha chayyeni</b> — <i>haaver</i> (turn away, Hiphil imperative of <i>avar</i>) — the eyes must be actively redirected from worthless things (<i>shav</i> = emptiness/vanity, same word as taking God's name in vain, Exod 20:7). Turning the eyes from vanity to the word revives. Cf. Ps 101:3.</p>", "38": "<p><b>haqem leavdecha imratechah asher leyiratchah</b> — <i>haqem</i> (establish/fulfill, Hiphil imperative of <i>qum</i>) — confirm the divine promise-word. <i>imratechah asher leyiratchah</i> (your word/promise given to those who fear you) — the promise has a specific recipient class: <i>yiratchah</i> (fearers of you). The psalmist claims membership in that class.</p>", "39": "<p><b>haaver cherpati asher yagorti ki mishpatechah tovim</b> — <i>haaver cherpati</i> (turn away my shame, Hiphil of <i>avar</i>) — the same verb as v37's eye-turning now applied to shame. <i>yagorti</i> (I dread, Qal perfect of <i>yagor</i>) — the psalmist dreads the shame that comes from appearing unfaithful. Ground of confidence: <i>mishpatechah tovim</i> (your decrees are good) — the decrees are not the source of shame but of vindication.</p>", "40": "<p><b>hine taavti lepiqqudecha betzidqatchah chayyeni</b> — <i>hine</i> (behold!) + <i>taavti</i> (I have longed) — the particle of presentation introduces the longing as exhibited fact before God. <i>betzidqatchah chayyeni</i> (by your righteousness give me life) — the request grounds life-giving not in the psalmist's obedience but in God's own righteousness. The He stanza closes with dependence on divine character, not human achievement.</p>", "41": "<p><b>VAV — viyavuuni chasadecha YHWH teshuatchah keimratechah</b> — <i>viyavuuni chasadecha</i> (let your steadfast love come to me, Qal jussive of <i>bo</i>) — the covenant-love approaching as an active arrival. <i>teshuatchah</i> (your salvation) — <i>chesed</i> and <i>yeshuah</i> arrive together. <i>keimratechah</i> (just as you have promised) — the appeal is to prior divine commitment: the promise anchors the petition.</p>", "42": "<p><b>vaeneh chorefi dabar ki vatachti bidhvarecha</b> — <i>vaeneh</i> (and I will answer) — when the <i>chesed</i> and salvation arrive, the psalmist will have a reply for the mocker. <i>dabar</i> (a word) — the answer to the taunt is simply the divine word. <i>vatachti bidhvarecha</i> (for I trusted in your word) — <i>batach</i> (trust, rely on) — the ground of the reply is not argument but trust in the promise.</p>", "43": "<p><b>val-tatzel mipi devar-emet ad-meod ki lemishpatecha yichalti</b> — <i>al-tatzel mipi</i> (do not snatch from my mouth, Hiphil jussive of <i>natzel</i>) — the truth-word could be taken away if divine support fails. <i>ki lemishpatecha yichalti</i> (for I have hoped in your decrees) — <i>yachal</i> (to wait, hope with patient expectancy) — hope is the inner resource that keeps truth-speech possible under pressure.</p>", "44": "<p><b>veeshmorah toratecha tamid leolam vaed</b> — the triple time formula: <i>tamid</i> (continually, without interruption), <i>leolam</i> (forever), <i>vaed</i> (and ever) — Torah-keeping declared without temporal limits. Three time-horizons: unbroken present, indefinite future, and beyond-future. Such vows are not humanly keepable without divine enabling — which is what the preceding petition requests.</p>", "45": "<p><b>vehithallech birchavah ki piqqudechah darashti</b> — <i>vehithallech birchavah</i> (and I will walk in a broad/spacious place) — <i>rachav</i> again: the freedom and expansiveness of covenant-living. <i>darashti</i> (I have sought/pursued) — the spacious walk flows from having sought (<i>darash</i>) the precepts: freedom is the fruit of diligent pursuit, not the absence of constraint.</p>", "46": "<p><b>vadabberah bedotecha lifne mlachim velo evosh</b> — <i>lifne mlachim</i> (before kings) — the highest social stakes: testimony before political power. <i>velo evosh</i> (and I will not be ashamed) — before the most powerful human audience, covenant-loyalty produces boldness. Cf. Paul's 'not ashamed of the gospel' (Rom 1:16) and the NT pattern of apostolic boldness before rulers.</p>", "47": "<p><b>veshataasha bemitzvotechah asher ahavti</b> — <i>veshataasha</i> (and I will delight, Hithpael) — cultivated rather than merely felt delight. <i>asher ahavti</i> (which I love) — <i>ahav</i> (love, the covenant-love word) applied to the commandments: Torah-keeping is not grudging compliance but love-expression.</p>", "48": "<p><b>veesa-chapai el-mitzvotechah asher ahavti veaasicha bechuqqechah</b> — <i>veesa-chapai</i> (I will lift up my hands toward, Qal cohortative of <i>nasa</i>) — the gesture of prayer and longing directed toward the commandments: the posture of worship applied to Torah. <i>asher ahavti</i> repeats from v47: the Vav stanza closes with double declaration of love for the commandments.</p>", "49": "<p><b>ZAYIN — zachar davarecha leavdecha al asher yichaltani</b> — <i>zachar davarecha</i> (remember your word to your servant) — the covenant-memory verb: God's remembering activates promise. <i>al asher yichaltani</i> (because/upon which you have given me hope) — the word that was given became the basis of hope; now the psalmist asks God to remember the very word that generated that hope.</p>", "50": "<p><b>zot nechamati beoni ki imratechah chiyatni</b> — <i>nechamati</i> (my comfort) — <i>nacham</i> (comfort, the Noah-name-meaning word) — consolation in affliction. <i>ki imratechah chiyatni</i> (because your word has kept me alive) — the divine utterance is life-giving: the word did not merely comfort but sustained biological existence.</p>", "51": "<p><b>zedim helitsuni ad-meod mitoratechah lo-natiti</b> — <i>helitsuni</i> (they mocked/scorned me, Hiphil of <i>lutz</i>) — the same root as <i>letz</i> (scoffer) in Ps 1:1. <i>ad-meod</i> (to a great degree) — the intensity of the mockery. <i>lo-natiti</i> (I have not swerved, Qal perfect of <i>natah</i>) — despite extreme social pressure, the psalmist has not bent away from Torah.</p>", "52": "<p><b>zacharti mishpatecha meolam YHWH vaenachem</b> — <i>zacharti mishpatecha meolam</i> (I recalled your ancient decrees) — the temporal depth of divine justice: <i>meolam</i> (from of old, from antiquity). <i>vaenachem</i> (Niphal of <i>nacham</i>) — comfort comes from remembering that YHWH's decrees have always been operative. Historical memory of God's consistency is the consolation for present suffering.</p>", "53": "<p><b>zilaphah achazatni mershaaim ozve toratechah</b> — <i>zilaphah</i> (burning horror/rage, from <i>zalaph</i> = to scorch) — an intense physical reaction: burning indignation seizes the psalmist. <i>mershaaim ozve toratechah</i> (at the wicked who forsake your law) — the burning is not personal anger but moral horror at covenant-abandonment. Righteous indignation at Torah-rejection is itself a form of Torah-love.</p>", "54": "<p><b>zimrot hayu-li chuqqechah beveyt megurai</b> — <i>zimrot</i> (songs, from <i>zamar</i>) — the statutes become song content. <i>beveyt megurai</i> (in the house of my sojourning/dwelling place) — <i>magor</i> (place of sojourn, temporary residence) — echoes v19's <i>ger</i>: the psalmist's earthly life is sojourning, and the statutes provide the songs of that sojourn. Pilgrimage music.</p>", "55": "<p><b>zacharti balaylah shimchah YHWH vaasherah toratechah</b> — <i>balaylah</i> (in the night) — night is the time of both danger and undistracted meditation. <i>zacharti shimchah</i> (I recalled your name) — remembering the divine name in the dark: covenant-identity anchors the psalmist when external light fails. <i>vaasherah toratechah</i> (and I kept your law) — nighttime name-remembering expresses itself in daytime Torah-keeping.</p>", "56": "<p><b>zot haytah li ki piqqudecha natzerti</b> — <i>zot haytah li</i> (this has been mine/my lot) — the demonstrative <i>zot</i> may refer to the comfort of previous verses or to the practice of nighttime remembrance. <i>piqqudecha natzerti</i> (I have kept/guarded your precepts) — <i>natzerti</i> (Qal perfect of <i>natzar</i>, to guard carefully) — the keeping of precepts as what has been distinctively given to the psalmist.</p>", "57": "<p><b>HETH — chelqi YHWH amarti lishmor devarecha</b> — <i>chelqi YHWH</i> (the LORD is my portion/share) — <i>chelek</i> (allotment, inherited portion) is the tribal-land vocabulary: each tribe received its <i>chelek</i> in Canaan. To declare YHWH as one's <i>chelek</i> is to claim God himself as one's inheritance instead of land (cf. Ps 16:5; Lam 3:24; Num 18:20 for the Levites). <i>amarti lishmor devarecha</i> — claiming YHWH as portion issues in covenant loyalty.</p>", "58": "<p><b>challiti fanechah bkol-libbi chonneni kimratechah</b> — <i>challiti fanechah</i> (I sought/stroked your face, Piel of <i>chalah</i>) — an unusual idiom: literally 'I made your face soft,' i.e., softened the divine countenance with entreaty. <i>bkol-libbi</i> (with all my heart) — the whole-heart petition. <i>chonneni kimratechah</i> (be gracious according to your word) — grace is requested on the basis of prior divine commitment.</p>", "59": "<p><b>chishavti derachai vaasheivah raglai el-edotechah</b> — <i>chishavti derachai</i> (I reconsidered/thought about my ways, Piel of <i>chashav</i>) — deliberate moral self-examination. <i>vaasheivah raglai</i> (and I turned my feet back, Hiphil of <i>shuv</i>) — repentance is a turning of the feet, not just the mind. The reckoning precedes and produces the turning.</p>", "60": "<p><b>charashti velo hitmahmahti lishmor mitzvotechah</b> — <i>charashti</i> (I hurried, Qal perfect of <i>charats</i> = to be decisive, sharp, quick) — the speed of obedience: no delay between conviction and action. <i>velo hitmahmahti</i> (and I did not delay, Hithpael of <i>mahal</i>) — the Hithpael is intensive-reflexive: I did not allow myself to linger. Prompt obedience signals genuine commitment.</p>", "61": "<p><b>chevley rshaaim ivvetuni toratechah lo shachachti</b> — <i>chevley rshaaim</i> (cords/snares of the wicked) — <i>chevel</i> (rope, cord — the binding snare). The psalmist is physically or socially entrapped by the wicked. <i>toratecha lo shachachti</i> (your law I have not forgotten) — captivity to enemies does not produce captivity to forgetting: external constraint cannot sever internal Torah-loyalty.</p>", "62": "<p><b>chatzot laylah aqum lehodot lach al mishpetei tzidqechah</b> — <i>chatzot laylah</i> (midnight) — the precise middle of the night, when gratitude overcomes sleep. <i>aqum lehodot</i> (I rise to give thanks) — <i>hodot</i> from <i>yadah</i> (acknowledge, give thanks) — the waking impulse is thanksgiving, not petition. <i>al mishpetei tzidqechah</i> (for your righteous decrees) — the decrees themselves are the object of thanksgiving.</p>", "63": "<p><b>chaver ani lekol asher yerauchah ulshomrei piqqudechah</b> — <i>chaver</i> (companion, friend, associate) — the psalmist claims fellow-membership with all who fear YHWH. <i>ulshomrei piqqudechah</i> (those who keep your precepts) — Torah-keeping creates community: the shared practice of the precepts constitutes the fellowship. Precept-keeping is not solitary achievement but communal identity.</p>", "64": "<p><b>chesed YHWH malah haaretz chuqqechah lammadeni</b> — <i>chesed YHWH malah haaretz</i> (the steadfast love of the LORD fills the earth) — the cosmic reach of divine <i>chesed</i>: not restricted to Israel but saturating the entire created order. <i>chuqqechah lammadeni</i> (teach me your statutes) — from the universal to the personal: the God whose love fills all creation is asked to teach the individual psalmist.</p>", "65": "<p><b>TETH — tov asita im-avdecha YHWH kidvarecha</b> — <i>tov asita</i> (you have dealt/done good, Qal perfect) — the Teth stanza opens by affirming God's goodness in dealing with the servant. <i>kidvarecha</i> (according to your word) — divine goodness is in line with the promise-word. The stanza will trace the goodness of affliction (vv67, 71), which seems to contradict 'good dealing' until recognized as discipline.</p>", "66": "<p><b>tov taam vada lammadeni ki bemitzvotechah heemanti</b> — <i>tov taam vada</i> (good discernment and knowledge, teach me) — <i>taam</i> (taste/discernment/judgment) is the wisdom faculty that distinguishes good from bad, the same word used for the taste of manna (Exod 16:31). <i>heemanti</i> (I have trusted/believed, Hiphil of <i>aman</i>) — trust in the commandments is the foundation on which discernment can be requested.</p>", "67": "<p><b>terem eeneh ani shogeg veattah amarti toratechah shamarti</b> — <i>terem eeneh</i> (before I was afflicted, I used to wander) — the retrospective confession: suffering revealed wandering that had not been visible before. <i>shogeg</i> (wandering, Qal participle of <i>shagag</i> = to go astray unintentionally) — the pre-affliction state was inadvertent wandering. <i>veattah... shamarti</i> (but now I keep your law) — affliction produced what ease could not. Cf. Heb 12:11.</p>", "68": "<p><b>tov-attah umetiv lammadeni chuqqecha</b> — <i>tov-attah umetiv</i> (you are good and you do good) — a double confession: God's essential character (<i>tov-attah</i>) and his active dealings (<i>metiv</i>, Hiphil of <i>yatav</i> = to do good). Everything God does participates in his essential goodness — including the affliction of v67. The request: this good God teaches good statutes.</p>", "69": "<p><b>taplu alai sheqer zedim ani bkol-libbi ettzor piqqudecha</b> — <i>taplu</i> (they have plastered/smeared, Qal perfect of <i>taphal</i> = to plaster, whitewash, smear) — lies applied like plaster over a surface: slander as whitewashing over truth. <i>bkol-libbi</i> (with all my heart) — the whole-heart response to slander is deeper Torah-keeping, not counter-slander.</p>", "70": "<p><b>tapash kahelev libbam ani toratecha shaashati</b> — <i>tapash kahelev libbam</i> (their heart is insensible/fat like tallow) — <i>tapash</i> (dull, insensible, like fat tissue unable to respond to stimulus). <i>helev</i> (fat, tallow — the non-feeling part of an animal body). The arrogant's fat heart contrasts with the psalmist's delight (<i>shaashati</i>) in the same divine Law.</p>", "71": "<p><b>tov-li ki-uneyti lemaan etlamed chuqqechah</b> — <i>tov-li ki-uneyti</i> (it was good for me that I was afflicted) — the paradox of redemptive suffering: the affliction is retrospectively assessed as good. <i>lemaan etlamed chuqqechah</i> (so that I might learn your statutes) — suffering is the pedagogical instrument by which statutes are learned beyond intellectual assent. Cf. Heb 5:8 (Christ learned obedience through suffering).</p>", "72": "<p><b>tov-li torat-picha mialphe zahav vakesef</b> — <i>torat-picha</i> (the instruction of your mouth) — Torah personalized through the divine mouth: not law as text but word as utterance. <i>mialphe zahav vakesef</i> (more than thousands of gold and silver) — the economic comparison: Torah valued above maximum conceivable material wealth. The Teth stanza closes with supreme valuation of Torah — the conclusion to which its paradoxes (affliction, slander, suffering) were building.</p>", "73": "<p><b>JOD — yadecha asuni vaychonnenuni havineni veelmedah mitzvotecha</b> — <i>yadecha asuni</i> (your hands made me/formed me) — <i>yad</i> (hand) as instrument of divine creation. <i>vaychonnenuni</i> (and established me, Polel of <i>kun</i>) — the Polel is intensive: carefully formed. <i>havineni veelmedah</i> (give me understanding so I may learn) — the creator is asked to complete his work: having formed the person, grant understanding to learn the commands. Creation and instruction belong to the same divine act.</p>", "74": "<p><b>yerauchah yeeru vi veyismachu ki lidvarecha yichalti</b> — <i>yerauchah yeeru vi</i> (those who fear you will see me and rejoice) — the witness dimension of personal salvation: the psalmist's rescue becomes evidence for the community of fearers. <i>yichalti</i> (I have hoped) — the basis of others' joy is the psalmist's hope in the word: trust in divine promise, when honored, encourages communal faith.</p>", "75": "<p><b>yadati YHWH ki-tzedek mishpatecha veemunah innitani</b> — <i>yadati</i> (I know, Qal perfect of <i>yada</i>) — certain knowledge. <i>tzedek mishpatecha</i> (your decrees are just/righteous) — the justice of the decrees is acknowledged even when they produce affliction. <i>veemunah innitani</i> (and in faithfulness you afflicted me) — <i>emunah</i> (faithfulness, reliability) as the quality of the divine affliction: it is not capricious but perfectly reliable as a covenant act. Cf. Heb 12:10.</p>", "76": "<p><b>yehi-na chasdecha lenadmeni kaasher amarta leeavdecha</b> — <i>yehi-na chasdecha</i> (let your steadfast love be, jussive + entreaty particle) — after affirming the justice of affliction (v75), the request is for comfort from divine love. <i>lenadmeni</i> (to comfort me) — <i>nacham</i> (to console). <i>kaasher amarta</i> (just as you promised) — the promise anchors the comfort request: YHWH has a track record of consoling those who suffer under faithful covenant discipline.</p>", "77": "<p><b>yavuuni rachamecha veechyeh ki toratechah shaashuai</b> — <i>rachamecha</i> (your compassion/tender mercies, plural of <i>rechem</i>) — the womb-mercy plural, denoting fullness of maternal-tender love. <i>veechyeh</i> (so that I may live) — life is the gift that compassion provides. <i>ki toratechah shaashuai</i> (for your law is my delight) — the delight in Torah is offered as the reason why life is desired: to live more fully in Torah-delight.</p>", "78": "<p><b>yevoshu zedim ki-sheqer ivvituni ani asicha bepiqqudecha</b> — <i>yevoshu zedim</i> (may the arrogant be shamed) — those who smeared lies (v69) should experience the shame they intended for the psalmist. <i>sheqer ivvituni</i> (they twisted/bent me with falsehood) — <i>ivvah</i> (to twist, bend, pervert). <i>ani asicha bepiqqudecha</i> (I will meditate on your precepts) — the psalmist's response to slander is meditation, not retaliation.</p>", "79": "<p><b>yashuvu li yerauchah veyodei edotechah</b> — <i>yashuvu</i> (may they return, Qal jussive of <i>shuv</i>) — the psalmist desires the return of the community of fearers to fellowship. <i>veyodei edotechah</i> (those who know your decrees) — knowledge of the decrees defines the community: they are those who have learned. The verse expresses longing for Torah-community, not just individual practice.</p>", "80": "<p><b>yehi-libbi tamim bechuqqechah lemaan lo evosh</b> — <i>yehi-libbi tamim</i> (let my heart be wholehearted/blameless, jussive) — <i>tamim</i> (the Noah-Abraham wholeness word, v1) applied now to the heart: not just blameless behavior but a blameless interior. <i>lemaan lo evosh</i> (so that I will not be ashamed) — the Yodh stanza closes with the shame-avoidance goal from v6: the request for a whole heart is ultimately a request not to be publicly exposed as inconsistent.</p>", "81": "<p><b>CAPH — kaltah naphshi liyshvatechah lidvarecha yichalti</b> — <i>kaltah naphshi</i> (my soul is exhausted/finished, Qal perfect of <i>kalah</i> = to be complete, come to an end, be consumed) — the soul reaches its limit, used up in waiting. <i>liyshvatechah</i> (for your salvation) — waiting is directional: exhaustion aimed at divine rescue. <i>lidvarecha yichalti</i> (in your word I have hoped) — hope sustains the exhausted soul: the word is the only thing keeping the waiting from becoming despair.</p>", "82": "<p><b>kalu einai leimratechah lemor matai tenachemeni</b> — <i>kalu einai</i> (my eyes are exhausted, same <i>kalah</i> as v81) — the eyes strain to see the fulfillment of the word until they are consumed. <i>matai tenachemeni</i> (when will you comfort me?) — the lament-form question: not 'will you?' but 'when?' — the psalmist has no doubt about eventual comfort but aches under the delay. Double exhaustion (soul and eyes) — the most acute crisis point in the psalm.</p>", "83": "<p><b>ki-hayyiti kened beashan chuqqechah lo shachachti</b> — <i>kened beashan</i> (like a wineskin in smoke) — a leather bottle hanging in a smoky tent becomes dry, shriveled, blackened, useless. The psalmist's condition is one of complete deterioration. <i>chuqqechah lo shachachti</i> (your statutes I have not forgotten) — even in the most deteriorated condition, the Torah-memory holds. The wineskin-body may be ruined; the inner attachment to the statutes remains.</p>", "84": "<p><b>mah yemei avdechah matai taaseh veshofetai berodphai</b> — <i>mah yemei avdechah</i> (how many are the days of your servant?) — a temporal complaint about brevity: the servant's days are few, and the enemy's harassment fills them. <i>matai taaseh veshofetai</i> (when will you execute judgment on my persecutors?) — the petition for divine justice is set against the backdrop of a finite lifespan.</p>", "85": "<p><b>karu-li zedim shichot asher lo kethoratechah</b> — <i>karu-li</i> (they dug for me, Qal perfect of <i>karah</i> = to dig) — the image of pit-digging for an enemy trap (cf. Ps 7:15; 57:6). <i>shichot</i> (pits/cisterns). <i>asher lo kethoratechah</i> (who do not follow your law) — the pit-diggers are defined as Torah-rejectors: their opposition to the psalmist flows from their opposition to the divine instruction.</p>", "86": "<p><b>kol-mitzvotechah emunah sheqer redefahuni ezreni</b> — <i>kol-mitzvotechah emunah</i> (all your commandments are faithful/trustworthy) — the reliability of the commandments stands in absolute contrast to the <i>sheqer</i> (falsehood) of the persecutors. <i>sheqer redefahuni</i> (they pursue me with falsehood). <i>ezreni</i> (help me!) — the bare cry for assistance: when all the theology of reliable commandments meets actual persecution, the response is the naked plea.</p>", "87": "<p><b>kimat kiluni vaaretz vaani lo-azavti piqqudechah</b> — <i>kimat kiluni vaaretz</i> (they almost destroyed me from the earth) — <i>kimat</i> (almost, nearly) — a narrow escape from annihilation. <i>vaani lo-azavti piqqudechah</i> (but I have not abandoned your precepts) — <i>azav</i> (to forsake, abandon) — the near-annihilation did not produce apostasy. Cf. v8's prayer 'do not abandon me': the psalmist asks God not to abandon him, and the psalmist does not abandon God's precepts.</p>", "88": "<p><b>kechasdechah chayyeni veeshmorah edat picha</b> — <i>kechasdechah chayyeni</i> (revive me according to your steadfast love) — the Kaph stanza closes with the same request as v81's opening: the exhausted, near-consumed soul asks for life from <i>chesed</i>. <i>edat picha</i> (the decrees of your mouth) — keeping is renewed through life; life enables keeping. The stanza moves from exhaustion through persecution to the grounded plea for <i>chesed</i>-life.</p>", "89": "<p><b>LAMED — leolam YHWH devarecha nitzav bashamayim</b> — the theological summit of the psalm. <i>leolam</i> (forever) + <i>nitzav</i> (stands fixed, Niphal participle of <i>natzav</i> = to set up, stand firm, be stationed) — the word is permanently stationed in the heavens: not merely lasting long but structurally fixed in the permanent realm. <i>bashamayim</i> (in the heavens) — above the contingency of human history. Cf. Isa 40:8; Matt 5:18; 24:35.</p>", "90": "<p><b>ledor vador emunatechah kananta aretz vataamud</b> — <i>ledor vador</i> (through every generation) — the temporal parallel to the spatial 'in the heavens' (v89): the word is fixed above and faithful across time. <i>emunatechah</i> (your faithfulness). <i>kananta aretz vataamud</i> (you established the earth and it stands) — creation's stability is the proof of divine faithfulness: the earth that continues to exist is a standing testimony to <i>emunah</i>.</p>", "91": "<p><b>lemishpatechah amadnu hayom ki hakol avadechah</b> — <i>lemishpatechah amadnu hayom</i> (they stand to this day according to your decrees) — the created order continues in existence because it obeys the divine decrees. <i>ki hakol avadechah</i> (for everything serves you) — <i>avad</i> (to serve/work) — all creation is in a servant relationship to YHWH: the stars, the seasons, the natural order all serve by continuing in the patterns the divine decrees established.</p>", "92": "<p><b>lulei toratechah shaashuai az avadti beoni</b> — <i>lulei</i> (if not, were it not for — the contrary-to-fact conditional) — the most vulnerable admission: had your law not been my delight, I would have perished in my affliction. <i>shaashuai</i> (my delight) — Torah-delight is identified as the survival mechanism. Without the delight-relationship with divine instruction, the psalmist would have died.</p>", "93": "<p><b>leolam lo-eshkach piqqudecha ki vam chiyitani</b> — <i>leolam lo-eshkach</i> (forever I will not forget) — forgetting (<i>shakhach</i>) is categorically excluded. <i>ki vam chiyitani</i> (for through them you gave me life) — the precepts are the medium of life: not symbolic of life but the actual channel through which life was granted. The psalmist owes existence itself to the precepts.</p>", "94": "<p><b>lecha ani hoshieni ki piqqudecha darashti</b> — <i>lecha ani</i> (I am yours) — the covenant ownership declaration: the psalmist claims belonging to YHWH as the ground for rescue. <i>hoshieni</i> (rescue me, Hiphil imperative of <i>yasha</i>) — 'I belong to you, therefore save what is yours.' <i>piqqudecha darashti</i> (I have sought your precepts) — the seeking of precepts demonstrates genuine belonging.</p>", "95": "<p><b>li qivvu rshaaim leabdeni edotechah etbonen</b> — <i>li qivvu rshaaim leabdeni</i> (the wicked lie in wait to destroy me) — <i>qivvu</i> (they wait in ambush, Piel of <i>qavah</i>) — the intensive form of waiting, with malicious intent. <i>edotechah etbonen</i> (I meditate on your decrees) — while enemies plot destruction, the psalmist's attention is fixed on the divine testimonies.</p>", "96": "<p><b>lekol tikla raiti qetz rechavah mitzvatchah meod</b> — <i>lekol tikla raiti qetz</i> (to every perfection I have seen a limit/end) — <i>tikla</i> (perfection, completion) — even the most perfect human achievement has a <i>qetz</i> (end, limit). <i>rechavah mitzvatchah meod</i> (your commandment is exceedingly broad) — <i>rachav</i> again: the commandment alone is without limit — boundlessly capacious. Everything human has a ceiling; the divine commandment has none.</p>", "97": "<p><b>MEM — mah-ahavti toratechah kol-hayom hi sichati</b> — <i>mah-ahavti</i> (how I love!) — the exclamation of love: <i>mah</i> as exclamatory particle (how much!). <i>ahav</i> (love, the covenant-love word applied to Torah). <i>kol-hayom hi sichati</i> (all day long it is my meditation) — <i>sichah</i> (meditation, voiced reflection). The Mem stanza opens with the declaration of Torah-love, the emotional register that has been building through all the affliction and doubt of earlier stanzas.</p>", "98": "<p><b>mechokmeni oyevai mitzvatchah ki leolam hi li</b> — <i>mechokmeni oyevai</i> (your commandment makes me wiser than my enemies) — wisdom exceeding the enemy comes not from intelligence but from the commandment. <i>ki leolam hi li</i> (for it is always with me) — the commandment's constant presence is the source of ongoing wisdom. The Torah-wise person has a permanent companion that enemies lack.</p>", "99": "<p><b>mikol-melammdai hiskalti ki edotechah sichah li</b> — <i>mikol-melammdai</i> (more than all my teachers) — the psalmist surpasses human teachers not through innate genius but because the divine decrees are the constant subject of meditation. <i>edotechah sichah li</i> (for your decrees are my meditation) — the decrees as teacher exceed all human instructors.</p>", "100": "<p><b>mizeqenim evatein ki piqqudechah natzerti</b> — <i>mizeqenim evatein</i> (I understand more than the elders) — <i>zaqen</i> (elder, the experienced sage) — wisdom normally associated with age is surpassed through Torah-keeping. <i>piqqudechah natzerti</i> (for I have kept/guarded your precepts) — obedience to precepts produces understanding that exceeds accumulated human experience.</p>", "101": "<p><b>mikal-orach ra kalati raglai lemaan eshmore devarecha</b> — <i>kalati raglai</i> (I have restrained my feet, Qal perfect of <i>kala</i> = to restrain, hold back) — an act of will: the feet must be actively held back from evil paths. <i>lemaan eshmore devarecha</i> (so that I might keep your word) — restraint from evil paths is purposive: it serves the positive end of word-keeping.</p>", "102": "<p><b>mimishpatechah lo-sarti ki attah horitani</b> — <i>lo-sarti</i> (I have not turned aside, Qal perfect of <i>sur</i>) — no departure from the decrees. <i>ki attah horitani</i> (for you yourself have taught me) — the <i>attah</i> (you, emphatic) is significant: not a human teacher, not tradition, but YHWH personally. The root <i>yrh</i> (Hiphil = to teach) is the root of <i>tôrāh</i>. The word that is kept is the word whose Giver was the teacher.</p>", "103": "<p><b>mah-nimlequ lechiki imratechah midevash lefi</b> — <i>mah-nimlequ</i> (how sweet they are, Niphal of <i>malaq</i> = to be smooth, sweet to the palate) — the sensory experience of Torah: tasted, not merely read. <i>lechiki</i> (to my palate, <i>chek</i> = palate/mouth) — the most internal taste organ. <i>midevash lefi</i> (than honey to my mouth) — honey is the biblical superlative of sweetness (cf. Ps 19:10). The comparison echoes Ezekiel eating the scroll (Ezek 3:3).</p>", "104": "<p><b>mipiqqudekhah etbonen al-ken saneti kol-orach shaqer</b> — <i>mipiqqudekhah etbonen</i> (from your precepts I gain discernment) — the precepts are the source of moral perception. <i>al-ken saneti kol-orach shaqer</i> (therefore I hate every path of falsehood) — <i>sane</i> (hate, strong aversion) is the moral response to gained discernment: understanding what is right necessarily produces hatred of its opposite. Love of Torah produces hatred of falsehood as a logical consequence.</p>", "105": "<p><b>NUN — ner-leraglai devarecha veor lentivati</b> — <i>ner-leraglai</i> (a lamp to my feet) — <i>ner</i> is a small clay oil lamp, casting light only a few feet ahead. The image is intimate and practical: not a searchlight illuminating distant horizons but light enough for the next step. <i>veor lentivati</i> (and a light for my path) — <i>or</i> (light, the creation-light of Gen 1:3). The word provides what is needed for the next step, not a complete map. Cited universally as the defining image of Scripture's function.</p>", "106": "<p><b>nishbati vaaqaymah lishmor mishpetei tzidqechah</b> — <i>nishbati vaaqaymah</i> (I have sworn and I will fulfill/confirm it, Niphal of <i>shava</i> + Hiphil of <i>qum</i>) — the double vow: first sworn, then enacted. <i>vaaqaymah</i> (and I will establish/keep it standing) — <i>qum</i> in the Hiphil: causing the oath to stand firm in practice. The oath responds to the lamp of v105: seeing the path, the psalmist commits to walking it.</p>", "107": "<p><b>naaineiti ad-meod YHWH chayyeni kidvarecha</b> — <i>naaineiti ad-meod</i> (I am deeply afflicted, intensely oppressed) — <i>anah</i> (Niphal = to be afflicted) intensified with <i>ad-meod</i> (to a very great degree). The affliction is described without specifying its cause, making the verse universally applicable. <i>chayyeni kidvarecha</i> (give me life as you promised) — the word-promise is the anchor for the cry from maximum affliction.</p>", "108": "<p><b>nidhvot pi retze-na YHWH umishpatechah lammdeni</b> — <i>nidhvot pi</i> (the freewill offerings of my mouth) — <i>nedavah</i> (voluntary/freewill offering, from <i>nadav</i> = to volunteer, give spontaneously) applied to spoken words: uncoerced, spontaneous praise. <i>retze-na</i> (accept, please) — the petition for divine acceptance of voluntary worship. The 'mouth-offerings' are placed alongside material temple offerings as valid covenant-worship.</p>", "109": "<p><b>naphshi vchapi tamid vetoratechah lo-shachachti</b> — <i>naphshi vchapi tamid</i> (my life is in my hand always) — the idiom 'to hold one's life in one's hand' (<i>naphshi bkhaph</i>) means to live constantly at risk, in perpetual danger (cf. Judg 12:3; 1 Sam 19:5). <i>vetoratechah lo-shachachti</i> (yet your law I have not forgotten) — constant mortal danger does not break Torah-loyalty.</p>", "110": "<p><b>natenu rshaaim pach li umipiqqudekhah lo-taiti</b> — <i>natenu rshaaim pach li</i> (the wicked laid a snare for me) — <i>pach</i> (snare/trap, the kind that springs closed). <i>umipiqqudekhah lo-taiti</i> (yet from your precepts I have not wandered, Qal perfect of <i>tah</i> = to wander, stray) — the wandering-root that closes the psalm (v176) appears here mid-psalm: the psalmist has not strayed despite the traps.</p>", "111": "<p><b>nachalti edotechah leolam ki-sasson libbi hemah</b> — <i>nachalti</i> (I have taken/received as inheritance, Qal perfect of <i>nachal</i>) — the land-inheritance verb: the decrees are received the way tribal portions are received, as permanent endowment. <i>leolam</i> (forever) — an eternal inheritance, not subject to the land-losses of history. <i>ki-sasson libbi hemah</i> (for they are the joy of my heart) — the inheritance produces joy: Torah-possession is treasure, not burden.</p>", "112": "<p><b>natiti libbi laasot chuqqechah leolam eqev</b> — <i>natiti libbi</i> (I have set/inclined my heart, Hiphil of <i>natah</i>) — the same verb as v36 where the psalmist asked God to incline the heart; here the psalmist describes having done so. <i>leolam eqev</i> (forever, to the very end) — the time-formula from v33 (<i>eqev</i> = to the last step/consequence) repeated: lifelong-to-the-end commitment.</p>", "113": "<p><b>SAMECH — seaphim saneti vetoratecha ahavti</b> — <i>seaphim</i> (the double-minded/wavering ones, plural of <i>seaph</i> = a divided branch, a fork) — those whose minds are split between Torah and its opposite: internally divided, half-committed. The word's root meaning of 'forked/divided' captures the half-heartedness the psalmist rejects. <i>vetoratecha ahavti</i> (but your law I love) — undivided love vs. divided mind.</p>", "114": "<p><b>sitri umagini attah lidhvarecha yichalti</b> — <i>sitri</i> (my shelter/hiding place) — <i>seter</i> (hiding place, refuge, cf. Ps 27:5; 91:1). <i>umagini</i> (and my shield) — <i>magen</i>. The two metaphors: <i>seter</i> hides the person from the enemy; <i>magen</i> deflects the assault. Together they cover both evasion and confrontation. <i>lidhvarecha yichalti</i> (in your word I have hoped) — shelter and shield are trusted because the word that promises them is trusted.</p>", "115": "<p><b>suru-mimmeni mereeyim veeetzerah mitzvot elohai</b> — <i>suru-mimmeni</i> (depart from me, Qal imperative of <i>sur</i>) — a direct command to evildoers. <i>veeetzerah mitzvot elohai</i> (so that I may observe the commands of my God) — the departure of evildoers is requested for a purpose: their presence apparently hinders the Torah-observance the psalmist desires. The community one inhabits affects the commands one can keep.</p>", "116": "<p><b>somcheni chimratechah veeechyeh veal-tivisheni misivri</b> — <i>somcheni</i> (sustain me, Qal imperative of <i>samach</i> = to lean on, support, prop up) — <i>samach</i> is the word for leaning one's hand on a sacrifice (Lev 1:4). <i>misivri</i> (from my hope) — <i>seber</i> (hope/expectation) — 'do not let my hope put me to shame': the hope in the word must not turn out to be an illusion.</p>", "117": "<p><b>seadeni veivashea veesheh bchukqechah tamid</b> — <i>seadeni</i> (support/brace me, Qal imperative of <i>saad</i> = to support, sustain, refresh — the bread-sustaining word of Ps 104:15) — structural support, as beams support a building. <i>veivashea</i> (and I will be saved) — salvation is the result of divine structural support, not personal strength. <i>veesheh bchukqechah tamid</i> — the gaze-commitment follows from being upheld.</p>", "118": "<p><b>salita kol-shogim mechuqqechah ki-sheqer tarmitam</b> — <i>salita</i> (you have rejected, Qal perfect of <i>salah</i> = to weigh, hence to reject as not weighing up) — a smelting metaphor: those who stray are rejected like underweight metal. <i>kol-shogim mechuqqechah</i> (all who stray from your statutes) — <i>shogim</i> (the inadvertent-wandering word from v10, v51). <i>ki-sheqer tarmitam</i> (for their deception is false/empty) — the deceptions of the strayers are themselves falsehood.</p>", "119": "<p><b>sigim hishbata kol-rshaaei aretz al-ken ahavti edotechah</b> — <i>sigim</i> (dross/slag, the waste product of metal smelting) — the wicked are the impurity skimmed off when metal is refined. <i>hishbata</i> (you have removed/caused to cease, Hiphil of <i>shavat</i>) — God removes the dross-wicked from the earth. <i>al-ken ahavti edotechah</i> (therefore I love your decrees) — because God purifies by removing the wicked, loving the decrees means aligning with the purification-principle.</p>", "120": "<p><b>samar mipachdecha besari umimishpatechah yarati</b> — <i>samar</i> (bristles/stands on end, Qal perfect of <i>samar</i> = to bristle, shudder) — the physical experience of divine dread: skin responds to the terror of YHWH. <i>besari</i> (my flesh) — the body responds to the encounter with divine holiness. <i>umimishpatechah yarati</i> (I am in awe of your judgments) — the Samekh stanza closes with somatic awe: the statutes are objects of holy dread, not just intellectual content.</p>", "121": "<p><b>AIN — asiti mishpat vatzedek al-tanicheni leoshqai</b> — <i>asiti mishpat vatzedek</i> (I have done justice and righteousness) — the declaration of innocence before God as the basis for petition. <i>al-tanicheni leoshqai</i> (do not hand me over to my oppressors, negative jussive of <i>nuach</i> = to leave, hand over) — since I have lived rightly, do not abandon me to those who have not. The Ayin stanza grounds its petitions in prior covenant conduct.</p>", "122": "<p><b>arev avdecha letov al-yaashuquni zedim</b> — <i>arev avdecha letov</i> (guarantee good things for your servant, Qal imperative of <i>arav</i> = to be surety, give pledge, co-sign) — the legal guarantor term: YHWH is asked to be the psalmist's guarantor, underwriting the servant's good outcome before divine court. <i>zedim</i> (the arrogant) — those who would trample without YHWH's co-signing of the petition.</p>", "123": "<p><b>einai kalu liyshvatechah velemimrat tzidqechah</b> — <i>einai kalu</i> (my eyes are exhausted, same <i>kalah</i> as vv81-82) — the Ayin stanza returns to the eye-exhaustion of Kaph: the crisis deepens. <i>liyshvatechah</i> (for your salvation) and <i>velemimrat tzidqechah</i> (for the fulfillment of your righteous word) — two parallel objects of the exhausted watch: salvation and the keeping of the righteous promise.</p>", "124": "<p><b>aseh im-avdecha kechasdecha vechuqqechah lammadeni</b> — <i>aseh im-avdecha kechasdecha</i> (deal with your servant according to your steadfast love) — <i>chesed</i> as the measure of divine dealing: not strict justice but covenant love. <i>vechuqqechah lammadeni</i> (and teach me your statutes) — the two requests flow from <i>chesed</i>: gracious treatment and instruction. One cannot receive instruction well unless treated with love.</p>", "125": "<p><b>avdecha ani havineni veeda edotechah</b> — <i>avdecha ani</i> (I am your servant) — the declaration of ownership/service again (cf. v94: 'I am yours'). <i>havineni veeda</i> (give me understanding and I will know) — understanding precedes knowing: discernment must be granted before knowledge can be received. The servant-status is the ground of the request: servants receive instruction from their masters.</p>", "126": "<p><b>et laasot laYHWH hepheru toratechah</b> — <i>et laasot laYHWH</i> (it is time for the LORD to act) — the most daring verse of the psalm: a call for divine intervention against those who have made the Torah void. <i>hepheru toratechah</i> (they have broken/made void your law) — <i>parar</i> (to break, frustrate, make void). The verse may also be read as justification for loving the commandments more intensely precisely when others violate them.</p>", "127": "<p><b>al-ken ahavti mitzvotecha mizahav umiaz</b> — <i>al-ken</i> (therefore) — the psalmist's response to Torah-violation by others (v126) is intensified Torah-love. <i>mizahav umiaz</i> (more than gold and fine gold) — <i>zahav</i> (gold) and <i>paz</i> (refined/pure gold, the finest grade) — both superlatives of material value. The economic comparison intensifies: not just thousands of coins but the finest gold.</p>", "128": "<p><b>al-ken kol-piqqudei kol yasharti kol-orach sheqer saneti</b> — <i>kol-piqqudei kol yasharti</i> (all your precepts in everything I consider right/straight) — <i>yashar</i> (straight, right). <i>kol-orach sheqer saneti</i> (every path of falsehood I hate) — the total love of the precepts produces total hatred of their opposite. No partial positions: comprehensive love generates comprehensive aversion to its antithesis.</p>", "129": "<p><b>PE — pelaot edotechah al-ken netzeratam naphshi</b> — <i>pelaot</i> (wonderful/marvelous things, Niphal participle of <i>pala</i>) — the decrees are characterized as <i>pele</i> (wonder), the word for extraordinary divine acts that exceed natural expectation. <i>netzeratam naphshi</i> (my whole being guards them) — not merely the mind but the whole person keeping watch over the wondrous decrees.</p>", "130": "<p><b>peter devarecha yair mevinin pethayyim</b> — <i>peter devarecha yair</i> (the opening/entrance of your words gives light) — <i>peter</i> (opening, first-opening — the word used for the firstborn who 'opens the womb' and for a doorway) — when the word is opened up, its light emerges. <i>mevinin pethayyim</i> (it gives understanding to the simple/open) — <i>pethi</i> (simple, naive, easily influenced — from <i>patah</i>, to be open) — wisdom literature's democratizing claim: the divine word illuminates not just experts but the open-hearted simple.</p>", "131": "<p><b>pi-paari vaeshap ki lemitzvotechah yaaveti</b> — <i>pi-paari vaeshap</i> (I opened my mouth and panted) — <i>pa'ar</i> (to open wide, gape) and <i>shaaph</i> (to pant, gasp) — two images of desperate longing: the wide-open mouth and the panting breath. The physicality is striking: Torah-desire expressed through the body's crisis-responses. <i>ki lemitzvotechah yaaveti</i> (for I craved your commandments) — <i>avah</i> (to desire/crave strongly).</p>", "132": "<p><b>peneh elai vachonneni kemishpat leohavei shemechah</b> — <i>peneh elai</i> (turn toward me, Qal imperative of <i>panah</i>) — the face-turning request: YHWH's attention directed toward the psalmist. <i>kemishpat leohavei shemechah</i> (as is your custom toward those who love your name) — <i>mishpat</i> (justice/norm/customary practice) — the petition claims the established divine pattern for name-lovers: YHWH has a track record of showing grace to them.</p>", "133": "<p><b>peamai koneni bidhvarecha veal-tishlet-bi kol-aven</b> — <i>peamai koneni</i> (establish my steps, Hiphil imperative of <i>kun</i>) — the footsteps must be structurally established by divine action. <i>veal-tishlet-bi kol-aven</i> (and let no iniquity have dominion/rule over me, Hiphil jussive of <i>shalat</i>) — sin personified as a would-be ruler. Cf. Gen 4:7 (sin crouching at the door, desiring to master Cain) and Rom 6:12 (do not let sin reign).</p>", "134": "<p><b>padeni meoshek adam veeshmorah piqqudechah</b> — <i>padeni meoshek adam</i> (redeem me from human oppression, Qal imperative of <i>padah</i> = to ransom, redeem by paying a price) — <i>padah</i> is the redemption word of the Exodus (Deut 9:26) applied to individual liberation from exploitation. <i>veeshmorah piqqudechah</i> (so I will keep your precepts) — liberation is for obedience: freed from oppression, the freed person can keep the precepts.</p>", "135": "<p><b>panecha haer beeavdecha velammadeni et-chuqqechah</b> — <i>panecha haer</i> (make your face shine, Hiphil imperative of <i>or</i>) — the Aaronic blessing language (Num 6:25: 'the LORD make his face shine upon you') becomes a personal petition. <i>velammadeni</i> (and teach me) — the shining face and the teaching statutes arrive together: illumination and instruction are the same divine act.</p>", "136": "<p><b>palgei-mayim yardu einai al lo-shameru toratechah</b> — <i>palgei-mayim yardu einai</i> (rivers/streams of water run down from my eyes) — <i>peleg</i> (canal, irrigation channel, artificial waterway) — the weeping is not mere tears but channeled streams. <i>al lo-shameru toratechah</i> (because they do not keep your law) — the object of weeping is corporate Torah-violation: the psalmist weeps not for personal sin but for others' faithlessness. Cf. Jer 9:1 and Lam 3:48-49.</p>", "137": "<p><b>TZADE — tzaddiq attah YHWH veyashar mishpatechah</b> — <i>tzaddiq attah YHWH</i> (you are righteous, O LORD) — the divine character-declaration opens the Tsade stanza. <i>veyashar mishpatechah</i> (and your decrees are upright/straight) — <i>yashar</i> (straight, upright) — the decrees reflect the character of their giver: a righteous God issues straight decrees.</p>", "138": "<p><b>tzivvita tzedek edotechah veemunah meod</b> — <i>tzivvita tzedek edotechah</i> (the decrees you commanded are righteousness/just) — <i>tzedek</i> (righteousness) as a quality of the commanded decrees: intrinsically right, not merely obligatory. <i>veemunah meod</i> (and very trustworthy/faithful) — <i>emunah</i> (faithfulness, reliability) — the decrees are both morally right and reliably consistent: two distinct but inseparable qualities.</p>", "139": "<p><b>tzimatni kinati ki shakhecho devarecha tzarai</b> — <i>tzimatni kinati</i> (my zeal has consumed me, Piel of <i>tzamat</i> = to cut off, destroy) — <i>kinah</i> (zeal, jealousy, burning devotion) consumes the psalmist: righteous zeal for the divine word burns the person who loves Torah while watching others neglect it. <i>ki shakhecho devarecha tzarai</i> (because my enemies have forgotten your words) — the specific cause of the consuming zeal.</p>", "140": "<p><b>tzeruphah imratechah meod veeavdecha ahevah</b> — <i>tzeruphah</i> (refined/purified, Qal passive of <i>tzaraph</i> = to smelt/refine metal) — the same metallurgical verb used of Joseph's testing in Ps 105:19 and of the divine word in Ps 12:6. The word has been through the fire and emerged pure. <i>veeavdecha ahevah</i> (and your servant loves it) — love for the tested-and-purified word: the refinement is the ground of love, not despite it.</p>", "141": "<p><b>tzair anochi venivzeh piqqudechah lo shachachti</b> — <i>tzair anochi venivzeh</i> (I am small and despised) — <i>tzair</i> (young, small, insignificant) + <i>nivzeh</i> (Niphal of <i>bazah</i> = to be despised — same word as Isa 53:3 for the Suffering Servant). Social insignificance and contempt are the psalmist's condition. <i>piqqudechah lo shachachti</i> (your precepts I have not forgotten) — the despised remember what the powerful forget.</p>", "142": "<p><b>tzidqatchah tzedek leolam vetoratecha emet</b> — <i>tzidqatchah tzedek leolam</i> (your righteousness is an everlasting righteousness) — the temporal infinity of divine righteousness: not a relative standard but a permanent ontological fact. <i>vetoratecha emet</i> (and your law is truth) — <i>emet</i> (truth, firmness, reliability — from <i>aman</i>) — the Torah is not merely accurate but constitutively true. Cf. John 17:17.</p>", "143": "<p><b>tzar umatzok metzeuni mitzvotechah shaashuai</b> — <i>tzar umatzok metzeuni</i> (distress and anguish have found/overtaken me) — <i>tzar</i> (narrow, adversity) + <i>matzok</i> (constriction, pressure) — two synonyms of crisis, both from roots meaning narrow/tight. <i>mitzvotechah shaashuai</i> (your commandments are my delight) — in maximum constriction, the commandments are still delight.</p>", "144": "<p><b>tzedek edotechah leolam havineni veechyeh</b> — <i>tzedek edotechah leolam</i> (your decrees are righteous forever) — closing the Tsade stanza with the theme it opened: divine righteousness that endures. <i>havineni veechyeh</i> (give me understanding and I will live) — understanding the eternal righteous decrees is the path to life.</p>", "145": "<p><b>KOPH — qarati vekol-lev aneni YHWH chuqqecha etzerah</b> — <i>qarati vekol-lev</i> (I called with all my heart) — the whole-heart formula combined with the cry (<i>qara</i>): the most intense petition of the psalm. <i>aneni YHWH</i> (answer me, O LORD) — the demand for divine response to maximum intensity prayer. <i>chuqqecha etzerah</i> (I will keep your statutes) — the commitment to obedience is the context for the petition.</p>", "146": "<p><b>qaratichah hoshieni veeshmorah edotechah</b> — <i>qaratichah hoshieni</i> (I called to you, save me) — salvation is the content of the call. <i>veeshmorah edotechah</i> (and I will keep your decrees) — rescue is sought for the purpose of covenant obedience. The Qoph stanza's double-call structure (vv145-146) shows the psalmist in maximum urgency.</p>", "147": "<p><b>qiddamti vanesheph vaashavea lidhvarecha yichalti</b> — <i>qiddamti vanesheph</i> (I am up before dawn, Piel of <i>qadam</i> = to go before, precede, meet eagerly) — the dawn is anticipated: the psalmist rises before the light to pray. <i>lidhvarecha yichalti</i> (in your word I have hoped) — hope drives the early rising: the word is expected to arrive, so the psalmist is already awake to receive it.</p>", "148": "<p><b>qidemu einai ashmurot lasiyach bidhvarecha</b> — <i>ashmurot</i> (watches of the night, the military divisions of the night) — the psalmist's eyes are open through the night watches. <i>lasiyach bidhvarecha</i> (to reflect on/converse with your word) — <i>siyach</i> (to muse, speak with oneself, converse) — the word is the nighttime companion, the subject of wakeful conversation when others sleep.</p>", "149": "<p><b>qoli shimah kechasdecha YHWH kemishpatecha chayyeni</b> — <i>qoli shimah</i> (hear my voice) — the cry for auditory divine attention. <i>kechasdecha</i> (according to your steadfast love) — <i>kemishpatecha chayyeni</i> (according to your justice give me life) — both the love-attribute and the justice-attribute of YHWH are invoked: <i>chesed</i> and <i>mishpat</i> are not in tension but both motivate divine life-giving.</p>", "150": "<p><b>qirvou rodeephai zimma metoratechah rachaqu</b> — <i>qirvou rodeephai zimma</i> (those who pursue wickedness are drawing near) — the wicked are close, actively approaching. <i>metoratechah rachaqu</i> (they are far from your law) — the spatial paradox: physically near to the psalmist, yet far from Torah. Physical proximity to an enemy combined with their distance from the law defines the crisis.</p>", "151": "<p><b>qarov attah YHWH vekol-mitzvotechah emet</b> — <i>qarov attah YHWH</i> (you are near, O LORD) — the counter-claim to v150's nearness of enemies: YHWH is nearer. <i>vekol-mitzvotechah emet</i> (and all your commandments are truth) — nearness and truth are the YHWH-counterpart to the enemy's proximity and wickedness. The Qoph stanza turns on this reversal: near enemies, but nearer LORD.</p>", "152": "<p><b>qedem yadaati meedotechah ki leolam yesadtam</b> — <i>qedem</i> (from ancient times, from of old) — the temporal depth of the psalmist's knowledge of the decrees: not recently acquired learning. <i>ki leolam yesadtam</i> (for you established them forever, Piel of <i>yasad</i> = to found, establish) — the decrees were founded to last forever: their permanence was their design from the beginning.</p>", "153": "<p><b>RESH — reeh onyi vachaltzeni ki toratecha lo shachachti</b> — <i>reeh onyi</i> (see my affliction/suffering) — <i>onyi</i> (<i>oni</i>, affliction, lowness) — the bare appeal for divine attention to suffering. <i>vachaltzeni</i> (and rescue me, Piel of <i>chalatz</i> = to draw out, pull free, extract) — a physical extraction image: being pulled free from affliction's grip. <i>ki toratecha lo shachachti</i> — Torah-remembrance in affliction justifies the rescue request.</p>", "154": "<p><b>rivah ribi uge'aleni leimratechah chayyeni</b> — <i>rivah ribi</i> (plead my case, Qal imperative of <i>riv</i> = to contend, litigate) — the internal accusative construction emphasizes the legal action: YHWH is asked to take up the case as plaintiff on the psalmist's behalf. <i>uge'aleni</i> (and redeem me, Qal imperative of <i>gaal</i>) — legal pleading and kinship-redemption paired: YHWH as both attorney and nearest relative. <i>leimratechah chayyeni</i> — the promise grounds the request for life.</p>", "155": "<p><b>rachok mersha'im yeshvuah ki chuqqechah lo darashtu</b> — <i>rachok mersha'im yeshvuah</i> (salvation is far from the wicked) — <i>rachok</i> (far) contrasts with v151's <i>qarov attah YHWH</i>. The causal chain is explicit: <i>ki chuqqechah lo darashtu</i> (they have not sought your statutes) — no seeking → no nearness → no salvation.</p>", "156": "<p><b>rachamechah rabbim YHWH kemishpatechah chayyeni</b> — <i>rachamechah rabbim</i> (your compassion is great/vast) — <i>rachamim</i> (plural of womb-compassion, maternal tenderness in abundance). <i>rabbim</i> (many, great) — the compassion is quantitatively vast. <i>kemishpatechah chayyeni</i> (according to your decrees give me life) — vast compassion and specific decrees both channel the life-request.</p>", "157": "<p><b>rabbim rodeephai vetzarai meedotechah lo-natiti</b> — <i>rabbim rodeephai vetzarai</i> (my persecutors and enemies are many) — the numerical weight of opposition. <i>meedotechah lo-natiti</i> (from your decrees I have not turned aside, Qal perfect of <i>natah</i>) — the many persecutors have not produced the slightest turn away from the decrees. Multiplied opposition, unmoved commitment.</p>", "158": "<p><b>raiti bogdim vaetqotatah asher imratechah lo shamaru</b> — <i>raiti bogdim</i> (I saw the faithless/treacherous, Qal of <i>bagad</i>) — <i>bogdim</i> are covenant-breakers. <i>vaetqotatah</i> (and I was grieved/loathed, Hithpoel of <i>qut</i> = to feel disgust, loathing) — strong disgust at covenant-betrayal. <i>asher imratechah lo shamaru</i> (because they did not keep your word) — betrayal of YHWH's word is the specific treachery that provokes the psalmist's loathing.</p>", "159": "<p><b>reeh ki-piqqudechah ahavti YHWH kechasdechah chayyeni</b> — <i>reeh ki-piqqudechah ahavti</i> (see that I love your precepts) — a presentation of evidence before the divine judge: 'look at my love.' <i>kechasdechah chayyeni</i> (according to your steadfast love give me life) — the Resh stanza's life-request appears for the fourth time (vv153-154, 156, 159): each time grounded differently (Torah-remembrance, kinship-redemption, vast compassion, precept-love).</p>", "160": "<p><b>rosh devarecha emet ulolam kol-mishpat tzidqechah</b> — <i>rosh devarecha emet</i> (the sum/entirety of your word is truth) — <i>rosh</i> (head, beginning, totality) — taken together, the whole of the divine word is truth. <i>ulolam kol-mishpat tzidqechah</i> (and forever every one of your righteous decrees) — each individual decree endures forever. The Resh stanza closes with the comprehensive-and-eternal nature of the divine word.</p>", "161": "<p><b>SHIN — sarim redefahuni chinnam umidhvarecha pachad libbi</b> — <i>sarim redefahuni chinnam</i> (rulers have pursued me without cause) — <i>sarim</i> (princes/officials) + <i>chinnam</i> (without cause — the same word in lament psalms for unjust persecution). <i>umidhvarecha pachad libbi</i> (but my heart trembles/stands in awe of your word) — <i>pachad</i> (dread/awe) applied not to the ruling persecutors but to the divine word: the psalmist fears the word, not the officials.</p>", "162": "<p><b>saas anochi al-imratechah kemotze shalal rav</b> — <i>saas anochi al-imratechah</i> (I rejoice over your word) — <i>sus</i> (rejoice, festive-joy). <i>kemotze shalal rav</i> (like someone finding great spoil) — <i>shalal</i> (spoil, plunder taken in battle) — the warrior's exultation at unexpected wealth of victory. The word is not merely reassuring comfort but the discovery of unexpected treasure at the moment of conflict.</p>", "163": "<p><b>sheqer saneti vaavtea toratecha ahavti</b> — <i>sheqer saneti vaavtea</i> (falsehood I hate and detest) — two verbs of rejection: <i>sane</i> (hate) and <i>ta'av</i> (abhor, detest, consider abominable). <i>toratecha ahavti</i> (your law I love) — the emotional poles stated baldly: hatred of falsehood and love of Torah are inversely proportional.</p>", "164": "<p><b>sheva bayom hillaltichah al mishpetei tzidqechah</b> — <i>sheva bayom</i> (seven times a day) — seven as the number of completeness: praise throughout the complete day. <i>hillaltichah</i> (I praise you, Piel perfect of <i>halal</i>) — the same root as <i>hallelujah</i>. The decrees generate not just obedience but constant, all-day praise.</p>", "165": "<p><b>shalom rav leohavei toratechah vein-lamo mikhshol</b> — <i>shalom rav</i> (great peace) — <i>shalom</i> (wholeness, completeness, flourishing) qualified by <i>rav</i> (great, abundant): the fullness of shalom. <i>leohavei toratechah</i> (to those who love your law) — recipients are Torah-lovers. <i>vein-lamo mikhshol</i> (and there is no stumbling block for them) — <i>mikhshol</i> (stumbling block, from <i>kashal</i> = to stumble) — great peace means an unobstructed path.</p>", "166": "<p><b>sivvarti liyshvatechah YHWH umitzvotechah asiti</b> — <i>sivvarti</i> (I have hoped, Piel of <i>sabar</i> = to wait hopefully, look for) — <i>sabar</i> emphasizes active looking-forward, watching for the expected arrival. <i>umitzvotechah asiti</i> (and your commandments I have done) — hope and action are simultaneous: hope in salvation does not suspend obedience but accompanies it.</p>", "167": "<p><b>shamrah naphshi edotechah vaahavam meod</b> — <i>shamrah naphshi</i> (my whole being/soul keeps, Qal perfect of <i>shamar</i>) — <i>naphshi</i> (my soul/whole person) as the subject of Torah-keeping: the entire person, not just the behavioral exterior. <i>vaahavam meod</i> (and I love them deeply/greatly) — <i>meod</i> (greatly, intensely) intensifying the love. The Shin stanza gathers the love-theme from v97 and brings it to peak expression.</p>", "168": "<p><b>shamarti piqqudechah vedotechah ki kol-derachai negdechah</b> — <i>kol-derachai negdechah</i> (all my ways are before you) — <i>neged</i> (before, in front of, in full view of) — the transparency of covenant life: nothing hidden from divine sight. The keeping of precepts and decrees is offered not as legal compliance but as life lived in full divine visibility. The Shin stanza closes with complete openness before YHWH.</p>", "169": "<p><b>TAV — tiqrav rinnati lefanechah YHWH kidvarecha havineni</b> — <i>tiqrav</i> (let it draw near/approach, Qal jussive of <i>qarav</i>) — the cry is asked to make its own journey toward the divine presence. <i>rinnati</i> (my ringing cry) — <i>rinnah</i> (the shout of distress or joy, the same word as Ps 118:15). <i>kidvarecha havineni</i> (according to your word give me understanding) — the word is the standard by which understanding is measured and granted.</p>", "170": "<p><b>tavo techinnati lefanechah kidvarecha hatzileni</b> — <i>tavo techinnati</i> (let my plea/supplication come before you, Qal jussive of <i>bo</i>) — <i>techinnah</i> (supplication, plea for grace, from <i>chanan</i>) — not a petition of right but of grace. <i>kidvarecha hatzileni</i> (according to your word rescue me) — rescue grounded in the promise: the word promises rescue, so rescue is requested.</p>", "171": "<p><b>tabbaeena sefatai tehillah ki telammadeni chuqqechah</b> — <i>tabbaeena</i> (let them pour forth/overflow, Qal jussive of <i>nava</i> = to bubble up, overflow) — lips as a spring that overflows with praise. <i>tehillah</i> (praise, the word of the Psalter's title: <i>tehillim</i>) — the psalms themselves are the overflow of lips taught by divine statutes. <i>ki telammadeni chuqqechah</i> (because you teach me your statutes) — praise is the response to divine teaching: instruction produces overflow.</p>", "172": "<p><b>taan leshoni imratechah ki kol-mitzvotechah tzedek</b> — <i>taan leshoni</i> (let my tongue answer/respond, Qal jussive of <i>anah</i>) — the tongue is responsive: it answers the divine word. <i>ki kol-mitzvotechah tzedek</i> (for all your commandments are righteousness) — the tongue can celebrate the word because the word is righteous: ethical integrity is the ground of doxological speech.</p>", "173": "<p><b>tehi-yadechah leozreni ki piqqudecha bacharti</b> — <i>tehi-yadechah leozreni</i> (let your hand be ready to help me) — <i>yad</i> (hand) as instrument of divine assistance. <i>ki piqqudecha bacharti</i> (for I have chosen your precepts, Qal perfect of <i>bachar</i>) — the election-verb turned toward the precepts: just as God chooses (<i>bachar</i>) Israel, the psalmist has chosen the divine precepts. This choice is the ground for requesting the helping hand.</p>", "174": "<p><b>taaveti liyshvatechah YHWH vetoratechah shaashuai</b> — <i>taaveti</i> (I have longed for, Qal perfect of <i>avah</i>) — the strong craving-desire word (cf. v131): the psalmist has craved the divine salvation. <i>vetoratechah shaashuai</i> (and your law is my delight) — the <i>shaashua</i> (delight) word used throughout the psalm returns: Torah-delight and salvation-longing belong together.</p>", "175": "<p><b>tichi naphshi utehallalecha umishpatechah yaazruni</b> — <i>tichi naphshi</i> (let me live, Qal jussive of <i>chayah</i>) — the life-petition that has recurred throughout the psalm reaches its penultimate expression. <i>utehallalecha</i> (and let me praise you, Piel jussive of <i>halal</i>) — life is requested for the purpose of praise: continued existence serves doxology. <i>umishpatechah yaazruni</i> (and let your decrees help me) — the decrees are not merely to be kept but are themselves a source of help.</p>", "176": "<p><b>taiti kaseh oved bachavdecha ki mitzvotechah lo shachachti</b> — the psalm's final verse and its most surprising turn. <i>taiti kaseh oved</i> (I have strayed like a lost/perishing sheep, Qal perfect of <i>tah</i> = to wander, go astray) — after 175 verses of aspiration, vowing, longing, and love, the psalm ends with confession of straying. <i>kaseh oved</i> (like a lost sheep, <i>oved</i> = perishing, lost — the same root as Ps 1:6 'the way of the wicked will perish'). <i>bachavdecha</i> (seek your servant) — the request is for a seeking shepherd, not a judging master. <i>ki mitzvotechah lo shachachti</i> (for your commandments I have not forgotten) — the final line is not a claim of perfection but of orientation: the lost sheep still knows to whom it belongs. The psalm that began with <i>ashre</i> (blessed) ends with confession of lostness — the only honest conclusion to 176 verses of aspiration is the recognition that the straying sheep needs to be found.</p>"}}

if __name__ == '__main__':
    book = 'psalms'
    source = 'mkt-original'
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f'  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge')
